mapper.select:
SELECT
    p.id AS property_id,
    (
        SELECT COUNT(*)
        FROM cctv_infos c
        WHERE MBRContains(p.search_mbr, c.location)
          AND ST_Distance_Sphere(
                POINT(p.longitude, p.latitude),
                POINT(ST_Y(c.location), ST_X(c.location))
              ) <= #{radiusM}
    ) AS cctv_count,
    (
        SELECT COUNT(*)
        FROM security_lights sl
        WHERE MBRContains(p.search_mbr, sl.location)
          AND ST_Distance_Sphere(
                POINT(p.longitude, p.latitude),
                POINT(ST_Y(sl.location), ST_X(sl.location))
              ) <= #{radiusM}
    ) AS security_light_count,
    (
        SELECT COUNT(*)
        FROM security_facilities sf
        WHERE sf.x IS NOT NULL
          AND sf.y IS NOT NULL
          AND sf.x != 0
          AND sf.y != 0
          AND sf.x BETWEEN
              (p.longitude * 20037508.34 / 180.0) - #{radiusM}
              AND (p.longitude * 20037508.34 / 180.0) + #{radiusM}
          AND sf.y BETWEEN
              (
                  LOG(TAN((90.0 + p.latitude) * PI() / 360.0))
                  / (PI() / 180.0) * 20037508.34 / 180.0
              ) - #{radiusM}
              AND (
                  LOG(TAN((90.0 + p.latitude) * PI() / 360.0))
                  / (PI() / 180.0) * 20037508.34 / 180.0
              ) + #{radiusM}
          AND ST_Distance_Sphere(
                POINT(p.longitude, p.latitude),
                POINT(
                    sf.x / 20037508.34 * 180.0,
                    180.0 / PI() * (
                        2.0 * ATAN(EXP((sf.y / 20037508.34 * 180.0) * PI() / 180.0))
                        - PI() / 2.0
                    )
                )
              ) <= #{radiusM}
    ) AS security_facility_count
FROM properties p
WHERE p.id = #{propertyId}
  AND p.location IS NOT NULL
  AND p.latitude BETWEEN -90 AND 90
  AND p.longitude BETWEEN -180 AND 180
  AND p.search_mbr IS NOT NULL
